mapper.select:
SELECT apt_cmplex_no
FROM mgmt_office
WHERE mgmt_ofc_no = #{mgmtOfcNo}

mapper.sql:
/* 1. 관리사무소 공지 일정 조회 */ SELECT BI.APT_CMPLEX_NO /** 아파트단지번호 */ , P.ANN_NO AS SCHEDULE_NO /** 일정번호 */ , 'NOTICE' AS SCHEDULE_TY /** 일정유형코드 */ , '공지' AS SCHEDULE_TY_NM /** 일정유형명 */ , P.TTL AS SCHEDULE_TTL /** 일정제목 */ , DBMS_LOB.SUBSTR(P.CN, 1000, 1) AS SCHEDULE_CN /** 일정내용 */ , '관리사무소' AS LOC_CN /** 장소내용 */ , TO_CHAR(NVL(P.PBLANC_BGNG_DT, P.REG_DTTM), 'YYYY-MM-DD') AS START_DT /** 일정시작일 */ , TO_CHAR(NVL(P.PBLANC_END_DT, NVL(P.PBLANC_BGNG_DT, P.REG_DTTM)), 'YYYY-MM-DD') AS END_DT /** 일정종료일 */ , CASE WHEN P.TOP_FIX_YN = 'Y' THEN 'RED' ELSE 'BLUE' END AS COLOR_CD /** 캘린더색상코드 */ , P.WRTR_ID AS RGTR_ID /** 등록자아이디 */ , NULL AS USER_NO /** 사용자번호 */ , NULL AS USER_NM /** 사용자명 */ , NULL AS SCHDL_STTS_CD , NULL AS SCHDL_STTS_NM , NULL AS SCHDL_STTS_CN , NULL AS SCHEDULE_COLOR_HEX FROM APT_ANN_BOARD_POST P INNER JOIN APT_BOARD_INSTANCE BI ON P.BOARD_NO = BI.BOARD_NO /** 게시판번호 연결 */ WHERE BI.APT_CMPLEX_NO = #{aptCmplexNo} /** 아파트단지번호 */ AND BI.USE_YN = 'Y' /** 게시판사용여부 */ AND P.DEL_YN = 'N' /** 삭제여부 */
/* 공지 시작일이 조회 월의 마지막 날보다 작거나 같으면 조회 대상 */ AND NVL(P.PBLANC_BGNG_DT, P.REG_DTTM) <= TO_DATE(#{monthEndDt}, 'YYYY-MM-DD')
/* 공지 종료일이 조회 월의 시작 날보다 크거나 같으면 조회 대상 */ AND NVL(P.PBLANC_END_DT, NVL(P.PBLANC_BGNG_DT, P.REG_DTTM)) >= TO_DATE(#{monthStartDt}, 'YYYY-MM-DD')
UNION ALL
/* 2. 단지 내 행사/공사 일정 조회 */ SELECT CS.APT_CMPLEX_NO, CS.SCHEDULE_NO,
/* * SCHDL_STTS_CD를 일정유형 코드로 사용 * 예: EVENT, CONSTRUCTION * * 왜 사용? * 제목에 '공사'라는 글자가 있는지 검사하지 않고, * DB 코드값으로 행사/공사를 정확히 구분하기 위해. */ CS.SCHDL_STTS_CD AS SCHEDULE_TY,
NVL(CC.CODE_NAME, CASE WHEN CS.SCHDL_STTS_CD = 'CONSTRUCTION' THEN '공사' ELSE '행사' END ) AS SCHEDULE_TY_NM,
CS.SCHDL_TTL AS SCHEDULE_TTL, CS.SCHDL_CN AS SCHEDULE_CN, CS.LOC_CN AS LOC_CN,
/* * COMPLEX_SCHEDULE에는 시작일/종료일 컬럼이 없으므로 * 현재는 REG_DT를 일정일자로 사용. */ TO_CHAR(TRUNC(CS.REG_DT), 'YYYY-MM-DD') AS START_DT, TO_CHAR(TRUNC(CS.REG_DT), 'YYYY-MM-DD') AS END_DT,
CASE WHEN CS.SCHDL_STTS_CD = 'CONSTRUCTION' THEN 'ORANGE' ELSE 'GREEN' END AS COLOR_CD,
CS.RGTR_ID AS RGTR_ID, NULL AS USER_NO, CS.RGTR_ID AS USER_NM,
CS.SCHDL_STTS_CD AS SCHDL_STTS_CD, CC.CODE_NAME AS SCHDL_STTS_NM, CC.CODE_CONTENT AS SCHDL_STTS_CN, NULL AS SCHEDULE_COLOR_HEX FROM COMPLEX_SCHEDULE CS LEFT JOIN COMMON_CODE CC ON CC.GROUP_CODE_NO = 'CMPLX_SCHDL_TY' AND CC.CODE_NO_CD = CS.SCHDL_STTS_CD AND CC.USE_YN = 'Y' WHERE CS.APT_CMPLEX_NO = #{aptCmplexNo} AND CS.SCHDL_STTS_CD IN ('EVENT', 'CONSTRUCTION') AND TRUNC(CS.REG_DT) BETWEEN TO_DATE(#{monthStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{monthEndDt}, 'YYYY-MM-DD')
UNION ALL
/* 3. 직원 휴가 일정 조회 */ SELECT MO.APT_CMPLEX_NO , VS.VACATION_SCHDL_NO AS SCHEDULE_NO , 'VACATION' AS SCHEDULE_TY , '직원휴가' AS SCHEDULE_TY_NM
/* * DB에는 ANNUAL, HALF_AM 같은 코드가 저장됨 * 화면에는 COMMON_CODE.CODE_NAME의 한글명(연차, 오전반차 등)을 보여줌 */ , NVL(CC.CODE_NAME, CASE VS.SCHDL_TTL WHEN 'ANNUAL' THEN '연차' WHEN 'HALF_AM' THEN '오전반차' WHEN 'HALF_PM' THEN '오후반차' WHEN 'SICK' THEN '병가' WHEN 'OFFICIAL' THEN '공가/경조사' WHEN 'SPECIAL' THEN '특별휴가' ELSE VS.SCHDL_TTL END ) AS SCHEDULE_TTL
/* * 예: 연차 - 개인 휴가 일정 #D6E8FF */ , NVL(CC.CODE_NAME, CASE VS.SCHDL_TTL WHEN 'ANNUAL' THEN '연차' WHEN 'HALF_AM' THEN '오전반차' WHEN 'HALF_PM' THEN '오후반차' WHEN 'SICK' THEN '병가' WHEN 'OFFICIAL' THEN '공가/경조사' WHEN 'SPECIAL' THEN '특별휴가' ELSE VS.SCHDL_TTL END ) || ' - ' || NVL( REGEXP_REPLACE(CC.CODE_CONTENT, '#[A-Fa-f0-9]{6}', ''), CASE VS.SCHDL_TTL WHEN 'ANNUAL' THEN '개인 휴가 일정' WHEN 'HALF_AM' THEN '오전 반일 휴가 일정' WHEN 'HALF_PM' THEN '오후 반일 휴가 일정' WHEN 'SICK' THEN '건강상의 사유로 인한 휴가 일정' WHEN 'OFFICIAL' THEN '공적 업무 또는 경조사 휴가 일정' WHEN 'SPECIAL' THEN '특별 사유 휴가 일정' ELSE '직원 휴가 일정' END ) AS SCHEDULE_CN
, '관리사무소' AS LOC_CN , TO_CHAR(VS.SCHDL_BGNG_DT, 'YYYY-MM-DD') AS START_DT , TO_CHAR(VS.SCHDL_END_DT, 'YYYY-MM-DD') AS END_DT , NVL(VS.COLOR_CD, 'PURPLE') AS COLOR_CD , M.USER_ID AS RGTR_ID , VS.USER_NO AS USER_NO , M.USER_NM AS USER_NM
/* * SCHDL_STTS_CD * 휴가상태코드. 여기서는 ANNUAL, HALF_AM 같은 휴가구분코드로 사용. */ , VS.SCHDL_TTL AS SCHDL_STTS_CD , NVL(CC.CODE_NAME, CASE VS.SCHDL_TTL WHEN 'ANNUAL' THEN '연차' WHEN 'HALF_AM' THEN '오전반차' WHEN 'HALF_PM' THEN '오후반차' WHEN 'SICK' THEN '병가' WHEN 'OFFICIAL' THEN '공가/경조사' WHEN 'SPECIAL' THEN '특별휴가' ELSE VS.SCHDL_TTL END ) AS SCHDL_STTS_NM , NVL( REGEXP_REPLACE(CC.CODE_CONTENT, '#[A-Fa-f0-9]{6}', ''), '직원 휴가 일정' ) AS SCHDL_STTS_CN
/* * CODE_CONTENT 안에 있는 #D6E8FF 같은 색상값만 추출 */ , NVL( REGEXP_SUBSTR(CC.CODE_CONTENT, '#[A-Fa-f0-9]{6}'), '#D6E8FF' ) AS SCHEDULE_COLOR_HEX
FROM MNGR_VACATION_SCHDL VS INNER JOIN MANAGER MG ON VS.USER_NO = MG.USER_NO INNER JOIN MGMT_OFFICE MO ON MG.MGMT_OFC_NO = MO.MGMT_OFC_NO INNER JOIN MEMBER M ON VS.USER_NO = M.USER_NO
/* * COMMON_CODE 조인 * VS.SCHDL_TTL = ANNUAL 같은 코드 * CC.CODE_NAME = 연차 같은 화면 표시명 */ LEFT JOIN COMMON_CODE CC ON CC.GROUP_CODE_NO = 'SCHDL_CLR' AND CC.CODE_NO_CD = VS.SCHDL_TTL AND CC.USE_YN = 'Y'
WHERE MO.APT_CMPLEX_NO = #{aptCmplexNo} AND MO.USE_YN = 'Y' AND VS.SCHDL_BGNG_DT <= TO_DATE(#{monthEndDt}, 'YYYY-MM-DD') AND VS.SCHDL_END_DT >= TO_DATE(#{monthStartDt}, 'YYYY-MM-DD')
UNION ALL
/* 4. 검침 일정 조회 - 한 달 내 동일 검침명 1건만 표시 */ SELECT CAL.APT_CMPLEX_NO, CAL.SCHEDULE_NO, CAL.SCHEDULE_TY, CAL.SCHEDULE_TY_NM, CAL.SCHEDULE_TTL, CAL.SCHEDULE_CN, CAL.LOC_CN, CAL.START_DT, CAL.END_DT, CAL.COLOR_CD, CAL.RGTR_ID, CAL.USER_NO, CAL.USER_NM, NULL AS SCHDL_STTS_CD, NULL AS SCHDL_STTS_NM, NULL AS SCHDL_STTS_CN, NULL AS SCHEDULE_COLOR_HEX FROM ( SELECT F.APT_CMPLEX_NO, 'METER_' || F.FACILITY_NO AS SCHEDULE_NO, 'METER' AS SCHEDULE_TY, '검침' AS SCHEDULE_TY_NM, F.FACILITY_NM || ' 검침' AS SCHEDULE_TTL, COUNT(*) OVER ( PARTITION BY F.APT_CMPLEX_NO, F.FACILITY_NM ) || '건 검침 완료' AS SCHEDULE_CN, F.LOC_CN AS LOC_CN, TO_CHAR(TRUNC(MH.METER_DT), 'YYYY-MM-DD') AS START_DT, TO_CHAR(TRUNC(MH.METER_DT), 'YYYY-MM-DD') AS END_DT, 'SKY' AS COLOR_CD, NULL AS RGTR_ID, NULL AS USER_NO, NULL AS USER_NM,
/* * ROW_NUMBER란? * 같은 그룹 안에서 1번, 2번, 3번처럼 순서를 매기는 함수. * * 왜 사용? * 한 달 안에 같은 검침명이 여러 번 있어도 최신 1건만 보여주기 위해. */ ROW_NUMBER() OVER ( PARTITION BY F.APT_CMPLEX_NO, F.FACILITY_NM || ' 검침' ORDER BY MH.METER_DT DESC ) AS RN FROM METER_HSTRY MH INNER JOIN FACILITY F ON MH.FACILITY_NO = F.FACILITY_NO WHERE F.APT_CMPLEX_NO = #{aptCmplexNo} AND F.USE_YN = 'Y' AND MH.METER_DT BETWEEN TO_DATE(#{monthStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{monthEndDt}, 'YYYY-MM-DD') + 0.99999 ) CAL WHERE CAL.RN = 1
UNION ALL
/* 5. 점검 일정 조회 - 중복 제거 */ SELECT CAL.APT_CMPLEX_NO , CAL.SCHEDULE_NO , CAL.SCHEDULE_TY , CAL.SCHEDULE_TY_NM , CAL.SCHEDULE_TTL , CAL.SCHEDULE_CN , CAL.LOC_CN , CAL.START_DT , CAL.END_DT , CAL.COLOR_CD , CAL.RGTR_ID , CAL.USER_NO , CAL.USER_NM , NULL AS SCHDL_STTS_CD , NULL AS SCHDL_STTS_NM , NULL AS SCHDL_STTS_CN , NULL AS SCHEDULE_COLOR_HEX FROM ( SELECT F.APT_CMPLEX_NO, 'CHECK_' || FH.FAC_CHK_HSTRY_NO AS SCHEDULE_NO, 'CHECK' AS SCHEDULE_TY, '점검' AS SCHEDULE_TY_NM, F.FACILITY_NM || ' 점검' AS SCHEDULE_TTL, FH.CHK_CN AS SCHEDULE_CN, NVL(F.LOC_CN, '단지 내 시설') AS LOC_CN, TO_CHAR(FH.CHK_DT, 'YYYY-MM-DD') AS START_DT, TO_CHAR(FH.CHK_DT, 'YYYY-MM-DD') AS END_DT, 'GRAY' AS COLOR_CD, NULL AS RGTR_ID, NULL AS USER_NO, NULL AS USER_NM, ROW_NUMBER() OVER ( PARTITION BY F.APT_CMPLEX_NO, F.FACILITY_NM ORDER BY FH.CHK_DT DESC, FH.FAC_CHK_HSTRY_NO DESC ) AS RN FROM FACILITY_CHECK_HSTRY FH INNER JOIN FACILITY F ON FH.FACILITY_NO = F.FACILITY_NO WHERE F.APT_CMPLEX_NO = #{aptCmplexNo} AND FH.CHK_DT BETWEEN TO_DATE(#{monthStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{monthEndDt}, 'YYYY-MM-DD') + 0.99999 ) CAL WHERE CAL.RN = 1

mapper.select:
/* kr.or.ddit.domain.apt.mgmtOffice.main.mapper.IAptScheduleCalendarMapper.selectScheduleCalendarList */ /* 단지 일정 캘린더 월별 일정 목록 조회 */
SELECT CAL.APT_CMPLEX_NO /** 아파트단지번호 */ , CAL.SCHEDULE_NO /** 일정번호 */ , CAL.SCHEDULE_TY /** 일정유형코드 */ , CAL.SCHEDULE_TY_NM /** 일정유형명 */ , CAL.SCHEDULE_TTL /** 일정제목 */ , CAL.SCHEDULE_CN /** 일정내용 */ , CAL.LOC_CN /** 장소내용 */ , CAL.START_DT /** 일정시작일 */ , CAL.END_DT /** 일정종료일 */ , CAL.COLOR_CD /** 캘린더색상코드 */ , CAL.RGTR_ID /** 등록자아이디 */ , CAL.USER_NO /** 사용자번호 */ , CAL.USER_NM /** 사용자명 */ , CAL.SCHDL_STTS_CD , CAL.SCHDL_STTS_NM , CAL.SCHDL_STTS_CN , CAL.SCHEDULE_COLOR_HEX FROM (
) CAL WHERE 1 = 1
AND CAL.SCHEDULE_TY = #{scheduleTy} /** 일정유형 검색 */
AND ( UPPER(CAL.SCHEDULE_TTL) LIKE '%' || UPPER(#{keyword}) || '%' /** 일정제목 검색 */ OR UPPER(CAL.SCHEDULE_CN) LIKE '%' || UPPER(#{keyword}) || '%' /** 일정내용 검색 */ OR UPPER(CAL.LOC_CN) LIKE '%' || UPPER(#{keyword}) || '%' /** 장소 검색 */ OR UPPER(CAL.USER_NM) LIKE '%' || UPPER(#{keyword}) || '%' /** 직원명 검색 */ )
ORDER BY CAL.START_DT ASC /** 일정시작일 오름차순 */ , CAL.SCHEDULE_TY ASC /** 일정유형 오름차순 */ , CAL.SCHEDULE_TTL ASC /** 일정제목 오름차순 */

SELECT COUNT(*) FROM (
) CAL WHERE 1 = 1
AND CAL.SCHEDULE_TY = #{scheduleTy}
AND ( UPPER(CAL.SCHEDULE_TTL) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(CAL.SCHEDULE_CN) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(CAL.LOC_CN) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(CAL.USER_NM) LIKE '%' || UPPER(#{keyword}) || '%' )

SELECT MG.USER_NO, M.USER_NM,
/* * empDisplayNm * 직원 선택창에 보여줄 표시명입니다. * * 예) * 김철수 (abcd***12) * * 왜 사용? * 동명이인 구분은 하되, 로그인ID 전체 노출은 막기 위해 사용합니다. */ M.USER_NM || ' (' || CASE WHEN M.USER_ID IS NULL THEN 'ID없음' WHEN LENGTH(M.USER_ID) <= 4 THEN SUBSTR(M.USER_ID, 1, 1) || '***' ELSE SUBSTR(M.USER_ID, 1, 4) || '***' || SUBSTR(M.USER_ID, -2) END || ')' AS EMP_DISPLAY_NM,
MG.MGMT_OFC_NO FROM MANAGER MG INNER JOIN MEMBER M ON MG.USER_NO = M.USER_NO WHERE MG.MGMT_OFC_NO = #{mgmtOfcNo} AND M.USER_YN = 'Y'
/* * 관리소장 제외 * 직원 휴가 등록 대상은 일반 직원만 보여주기 위해 제외합니다. */ AND M.USER_NM NOT LIKE '%관리소장%'
ORDER BY M.USER_NM ASC

/* kr.or.ddit.domain.apt.mgmtOffice.main.mapper.IAptScheduleCalendarMapper.selectNextVacationScheduleNo */
/* 직원 휴가 일정번호 채번 */

SELECT
    'VAC' || LPAD(SEQ_MNGR_VACATION_SCHDL.NEXTVAL, 6, '0')    /** 휴가일정번호 */
FROM DUAL

SELECT * FROM ( SELECT A.*, ROWNUM RN FROM ( SELECT CAL.APT_CMPLEX_NO ,CAL.SCHEDULE_NO ,CAL.SCHEDULE_TY ,CAL.SCHEDULE_TY_NM ,CAL.SCHEDULE_TTL ,CAL.SCHEDULE_CN ,CAL.LOC_CN ,CAL.START_DT ,CAL.END_DT ,CAL.COLOR_CD ,CAL.RGTR_ID ,CAL.USER_NO ,CAL.USER_NM , CAL.SCHDL_STTS_CD , CAL.SCHDL_STTS_NM , CAL.SCHDL_STTS_CN , CAL.SCHEDULE_COLOR_HEX FROM (
) CAL WHERE 1 = 1
AND CAL.SCHEDULE_TY = #{scheduleTy}
AND ( UPPER(CAL.SCHEDULE_TTL) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(CAL.SCHEDULE_CN) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(CAL.LOC_CN) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(CAL.USER_NM) LIKE '%' || UPPER(#{keyword}) || '%' )
ORDER BY CAL.START_DT ASC, CAL.SCHEDULE_TY ASC, CAL.SCHEDULE_TTL ASC ) A WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

mapper.insert:
/* kr.or.ddit.domain.apt.mgmtOffice.main.mapper.IAptScheduleCalendarMapper.insertVacationSchedule */
/* 직원 휴가 일정 등록 */

INSERT INTO MNGR_VACATION_SCHDL (
                                  VACATION_SCHDL_NO      /** 휴가일정번호 */
                                , SCHDL_BGNG_DT          /** 일정시작일자 */
                                , SCHDL_END_DT           /** 일정종료일자 */
                                , SCHDL_TTL              /** 일정제목 */
                                , COLOR_CD               /** 캘린더색상코드 */
                                , REG_DT                 /** 등록일자 */
                                , USER_NO                /** 사용자번호 */
) VALUES (
           #{scheduleNo}
         , TO_DATE(#{startDt}, 'YYYY-MM-DD')
         , TO_DATE(#{endDt}, 'YYYY-MM-DD')
         , #{scheduleSttsCd}
         , NVL(#{colorCd}, 'PURPLE')
         , SYSDATE
         , #{userNo}
         )

mapper.delete:
/* kr.or.ddit.domain.apt.mgmtOffice.main.mapper.IAptScheduleCalendarMapper.deleteVacationSchedule */
/* 직원 휴가 일정 삭제 */

DELETE FROM MNGR_VACATION_SCHDL
WHERE VACATION_SCHDL_NO = #{scheduleNo}     /** 휴가일정번호 */
  AND USER_NO IN (
    SELECT
        USER_NO                       /** 사용자번호 */
    FROM MANAGER
    WHERE MGMT_OFC_NO = #{mgmtOfcNo}   /** 관리사무소번호 */
)
